create table dirkspzm32.ts_job_items_log (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    ts_job_name          varchar2(50 char) not null enable,
    job_item_pos         number(*, 0) not null enable,
    job_item_type        varchar2(20 char) not null enable,
    status_text          varchar2(255 char),
    rep_name             varchar2(100 char),
    rep_gruppe           varchar2(100 char),
    rep_params           clob,
    export_type          varchar2(20 char),
    input_file_mask      varchar2(255 char),
    input_filename       varchar2(255 char),
    output_filename      varchar2(255 char),
    cmd_filename         varchar2(255 char),
    cmd_params           varchar2(255 char),
    printer_name         varchar2(255 char),
    send_to_group_id     number(*, 0),
    send_to_login_id     number(*, 0),
    send_to_e_mail       varchar2(255 char),
    job_item_data        clob,
    start_time           date,
    exec_duration_sec    number(*, 12),
    modified_by_login_id number(*, 0),
    last_modified_time   date,
    rep_id               number(*, 0),
    copy_to_output_dir   varchar2(1 char) default 'T',
    delete_criteria      varchar2(255 char) not null enable,
    job_item_log_id      number(*, 0) not null enable
);

alter table dirkspzm32.ts_job_items_log
    add constraint pk_ts_job_items_log
        primary key ( sid,
                      firma_nr,
                      job_item_log_id )
            using index enable;


